#include <stdio.h>
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int arr[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        int count = 0;
        for (int i = 0; i < n; i++) {
            int num = arr[i];
            int sum = 0;
            int temp = num;
            int digitCount = 0;
            while (temp != 0) {
                digitCount++;
                temp /= 10;
            }
            temp = num;
            while (temp != 0) {
                int digit = temp % 10;
                sum += (int) pow(digit, digitCount);
                temp /= 10;
            }
            if (sum == num) {
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

