import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            int n = scanner.nextInt();
            int[] arr = new int[n];
            for (int i = 0; i < n; i++) {
                arr[i] = scanner.nextInt();
            }
            int count = 0;
            for (int i = 0; i < n; i++) {
                int num = arr[i];
                int sum = 0;
                int temp = num;
                int digitCount = 0;
                while (temp != 0) {
                    digitCount++;
                    temp /= 10;
                }
                temp = num;
                while (temp != 0) {
                    int digit = temp % 10;
                    sum += (int) Math.pow(digit, digitCount);
                    temp /= 10;
                }
                if (sum == num) {
                    count++;
                }
            }
            System.out.println(count);
        }
    }
}

