const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let t;
let n;
let arr;
readline.on('line', line => {
    if (i == 0) {
        t = parseInt(line);
        i++;
    } else if (i == 1) {
        n = parseInt(line);
        i++;
    } else {
        arr = line.split(' ').map(num => parseInt(num));
        let count = 0;
        for (let j = 0; j < n; j++) {
            let num = arr[j];
            let sum = 0;
            let temp = num;
            let digitCount = 0;
            while (temp != 0) {
                digitCount++;
                temp = Math.floor(temp / 10);
            }
            temp = num;
            while (temp != 0) {
                let digit = temp % 10;
                sum += Math.pow(digit, digitCount);
                temp = Math.floor(temp / 10);
            }
            if (sum == num) {
                count++;
            }
        }
        console.log(count);
        i = 1;
        t--;
        if (t == 0) {
            process.exit();
        }
    }
});

